import { ZodError } from "zod";
import status13 from "http-status";
import { PrismaClientKnownRequestError as PrismaClientKnownRequestError2, PrismaClientValidationError as PrismaClientValidationError2 } from "@prisma/client/runtime/client";
var globalErrorHandler = (err, req, res, next) => {
  if (process.env.NODE_ENV === "development") {
    console.log(err);
  }
  let statusCode = status13.INTERNAL_SERVER_ERROR;
  let message = err.message || "Internal Server Error";
  let errorSources = [];
  let stack;
  if (err instanceof ZodError) {
    statusCode = status13.UNPROCESSABLE_ENTITY;
    message = "Validation failed";
    errorSources = err.issues.map((issue) => ({
      path: issue.path.join("=>"),
      message: issue.message
    }));
    stack = err.stack;
  } else if (err instanceof PrismaClientKnownRequestError2) {
    stack = err.stack;
    if (err.code === "P2002") {
      statusCode = status13.CONFLICT;
      message = "Duplicate entry found";
      errorSources = [{
        path: err.meta?.target?.join(", ") || "",
        message: `${err.meta?.target?.join(", ")} already exists`
      }];
    } else if (err.code === "P2025") {
      statusCode = status13.NOT_FOUND;
      message = "Record not found";
      errorSources = [{
        path: "",
        message: err.meta?.cause || "Requested record does not exist"
      }];
    } else if (err.code === "P2003") {
      statusCode = status13.BAD_REQUEST;
      message = "Invalid reference";
      errorSources = [{
        path: err.meta?.field_name || "",
        message: "Related record does not exist"
      }];
    } else {
      statusCode = status13.BAD_REQUEST;
      message = "Database error occurred";
      errorSources = [{ path: "", message: err.message }];
    }
  } else if (err instanceof PrismaClientValidationError2) {
    statusCode = status13.BAD_REQUEST;
    message = "Prisma validation error";
    errorSources = [{ path: "", message: err.message }];
    stack = err.stack;
  } else if (err instanceof AppError) {
    statusCode = err.statusCode;
    message = err.message;
    stack = err.stack;
    errorSources = [{ path: "", message: err.message }];
  } else if (err instanceof Error) {
    statusCode = status13.INTERNAL_SERVER_ERROR;
    message = err.message;
    stack = err.stack;
    errorSources = [{ path: "", message: err.message }];
  }
  res.status(statusCode).json({
    success: false,
    message,
    errorSources,
    error: process.env.NODE_ENV === "development" ? err : void 0,
    stack: process.env.NODE_ENV === "development" ? stack : void 0
  });
};

