// src/modules/payment/payment.services.ts
var handleStripeWebhookEvent = async (event) => {
  const isExistPayment = await prisma.payment.findFirst({
    where: {
      stripeEventId: event.id
    }
  });
  if (isExistPayment) {
    console.log(`event id ${event.id} is already processed`);
    return { message: `event id ${event.id} is already processed` };
  }
  switch (event.type) {
    case "checkout.session.completed": {
      const session = event.data.object;
      const bookingId = session.metadata?.bookingId;
      const paymentId = session.metadata?.paymentId;
      if (!bookingId || !paymentId) {
        console.log("Missing appointmentId or paymentId in session metadata");
        return { message: "Missing appointmentId or paymentId in session metadata" };
      }
      const booking = await prisma.booking.findFirst({
        where: {
          id: bookingId
        }
      });
      if (!booking) {
        console.error(`Appointment with id ${bookingId} not found`);
        return { message: `Appointment with id ${bookingId} not found` };
      }
      await prisma.$transaction(async (tx) => {
        await tx.booking.update({
          where: {
            id: bookingId
          },
          data: {
            paymentStatus: session.payment_status === "paid" ? PaymentStatus.PAID : PaymentStatus.UNPAID,
            bookingStatus: session.payment_status === "paid" ? BookingStatus.CONFIRMED : BookingStatus.PENDING
          }
        });
        await tx.payment.update({
          where: {
            id: paymentId
          },
          data: {
            stripeEventId: event.id,
            status: session.payment_status === "paid" ? PaymentStatus.PAID : PaymentStatus.UNPAID,
            paymentGatewayData: session
          }
        });
      });
      console.log(`Processed checkout.session.completed for booking ${booking} and payment ${paymentId}`);
      break;
    }
    case "checkout.session.expired": {
      const session = event.data.object;
      console.log(`Checkout session ${session.id} expired. Marking associated payment as failed.`);
      break;
    }
    case "payment_intent.payment_failed": {
      const session = event.data.object;
      console.log(`payment ${session.id} failed. Marking associated payment as failed.`);
      break;
    }
    default:
      console.log(`Unhandled event type ${event.type}`);
  }
  return { message: `Webhook Event ${event.id} processed successfully` };
};
var paymentServices = {
  handleStripeWebhookEvent
};

// src/modules/payment/payment.controller.ts
var handleStripeWebhooEvent = catchAsync_default(async (req, res) => {
  const singnature = req.headers["stripe-signature"];
  const secrate = envVar.STRIPE_WEBHOOK_SECRET;
  if (!singnature || !secrate) {
    console.error("Missing webhook secrate or singnature");
    return res.status(status14.BAD_REQUEST).json({ message: "Missing webhook secrate or singnature" });
  }
  let event;
  try {
    event = stripe.webhooks.constructEvent(req.body, singnature, secrate);
  } catch (error) {
    console.error("proccessing stripe error", error);
    return res.status(status14.BAD_REQUEST).json({ message: "proccessing stripe error" });
  }
  try {
    const result = await paymentServices.handleStripeWebhookEvent(event);
    sendResponse_default(
      res,
      status14.OK,
      "Stripe webhook event processed successfully",
      result
    );
  } catch (error) {
    console.log("prisma error is occured");
    return res.status(status14.BAD_REQUEST).json({
      success: false,
      message: "Error handling Stripe webhook event",
      error
    });
  }
});
var paymentController = {
  handleStripeWebhooEvent
};

